const items = $input.all();  // LLM text outputs
const allClassifications = [];

for (let i = 0; i < items.length; i++) {
  const llmItem = items[i];
  const rawText = llmItem.json.text;
  console.log(`Item ${i} raw: ${rawText.slice(0, 100)}...`);

  // Skip explicit empties
  if (rawText.trim() === '{}' || rawText.trim() === '{ }' || rawText.trim() === '') {
    console.log(`Item ${i}: Explicit empty - skipped`);
    continue;
  }

  let cls = {};
  try {
    // Aggressive unescape for n8n/LLM double-escaping
    let cleaned = rawText
      .replace(/\\\\n/g, ' ')                    // \\n → space
      .replace(/\\\\"/g, '"')                   // \\" → "
      .replace(/\\\\\\\\"/g, '\\"')             // \\\\" → \"
      .replace(/\\\\\\\\/g, '\\')               // Escaped backslashes
      .replace(/\\\\t/g, '') 
      .replace(/\\\\r/g, '')
      .trim();

    // Extract outermost JSON (handles nested braces)
    const jsonMatch = cleaned.match(/\{[^{}]*(?:\{[^{}]*\}[^{}]*)*\}/);
    if (!jsonMatch) {
      console.log(`Item ${i}: No JSON match in "${cleaned.slice(0, 100)}"`);
      continue;
    }

    cls = JSON.parse(jsonMatch[0]);
    console.log(`Parsed item ${i}:`, cls);
  } catch (e) {
    console.log(`Parse fail ${i}: ${e.message}`);
    console.log(`Raw snippet: ${rawText.slice(0, 200)}`);
    continue;
  }

  // REQUIRED fields for Agent 3
  if (!cls.pmid || !cls.association_id) {
    console.log(`Skipped item ${i}: missing pmid(${cls.pmid}) OR association_id(${cls.association_id})`);
    continue;
  }

  // ✅ Map to exact DB CHECK constraint enums
  const dbStudyTypes = {
    'invitro': 'in_vitro',
    'invivo': 'in_vivo',
    'clinicaltrial': 'clinical_trial', 
    'review': 'review',
    'metaanalysis': 'meta_analysis',
    'casestudy': 'case_study'
  };

  const dbLevels = {
    'preliminary': 'preliminary',
    'established': 'established', 
    'conclusive': 'conclusive',
    'insufficient': 'insufficient'
  };

  const standardized = {
    pmid: String(cls.pmid),                    // Keep as string for n8n
    herb_id: parseInt(cls.herb_id) || null,
    association_id: parseInt(cls.association_id),
    study_type: dbStudyTypes[cls.study_type?.toLowerCase()] || 'review',
    validation_level: dbLevels[cls.validation_level?.toLowerCase()] || 'preliminary',
    phytochemicals: cls.phytochemicals || [],
    biological_targets: cls.targets || [],
    sample_size: cls.sample_size !== undefined ? parseInt(cls.sample_size) || null : null,
    p_value: cls.p_value !== undefined ? parseFloat(cls.p_value) || null : null,
    significance_reported: Boolean(cls.significance_reported),
    llm_confidence: parseFloat(cls.llm_confidence) || 0.0,
    source_item: i
  };

  allClassifications.push(standardized);
  console.log(`✅ Accepted ${i}: ${cls.pmid} (${standardized.study_type}) conf=${standardized.llm_confidence}`);
}

const filtered = allClassifications.filter(c => c.pmid && c.association_id && c.herb_id);

return [{
  json: {
    classifications: filtered,
    total_accepted: filtered.length,
    total_attempted: items.length,
    skipped: items.length - filtered.length,
    sample: JSON.stringify(filtered.slice(0, 2), null, 2),
    avg_confidence: filtered.length ? (filtered.reduce((sum, c) => sum + c.llm_confidence, 0) / filtered.length).toFixed(3) : 0
  }
}];

// Minimal array/string cleanup only
const item = $input.item.json;
return [{
  json: {
    ...item,
    // Ensure arrays are arrays
    phytochemicals: Array.isArray(item.phytochemicals) ? item.phytochemicals : [],
    biological_targets: Array.isArray(item.biological_targets) ? item.biological_targets : [],
    // Booleans/numbers safe already
    significance_reported: Boolean(item.significance_reported),
    llm_confidence: parseFloat(item.llm_confidence) || 0
  }
}];

const items = $input.all();

const toTextArray = (arr) => {
  if (!Array.isArray(arr) || arr.length === 0) return '{}';
  const escapeSql = (v) => {
    v = String(v);
    v = v.replace(/'/g, "''");
    v = v.replace(/\\/g, "\\\\");
    v = v.replace(/\0/g, '');
    v = v.replace(/"/g, '\\"');
    return `"${v}"`;
  };
  return `{${arr.map(escapeSql).join(',')}}`;
};

const cleaned = [];
for (const item of items) {
  const cls = item.json;

  // ✅ CRITICAL: Use source_item to get ORIGINAL pmid from raw batch
  // Never trust LLM-returned pmid
  const trustedPmid = parseInt(cls.source_pmid || cls.pmid);
  const trustedHerbId = parseInt(cls.source_herb_id || cls.herb_id);
  const trustedAssocId = parseInt(cls.source_association_id || cls.association_id);

  if (!trustedPmid || !trustedHerbId || !trustedAssocId) continue;

  cleaned.push({
    pmid: trustedPmid,          // ← From raw input, NOT LLM
    herb_id: trustedHerbId,
    association_id: trustedAssocId,
    study_type: cls.study_type || 'review',
    validation_level: cls.validation_level || 'insufficient',
    phytochemicals_identified: toTextArray(cls.phytochemicals),
    biological_targets: toTextArray(cls.biological_targets),
    sample_size: cls.sample_size ? parseInt(cls.sample_size) : null,
    p_value: cls.p_value ? parseFloat(cls.p_value) : null,
    significance_reported: Boolean(cls.significance_reported),
    llm_confidence: parseFloat(cls.llm_confidence) || 0.7,
    classification_notes: '',
    source_item: parseInt(cls.source_item) || null
  });
}

console.log(`Prepared ${cleaned.length}/${items.length} records for DB`);
return cleaned.map(item => ({ json: item }));
